SELECT COUNT(*)
FROM pt_private_order
WHERE member_id = #{memberId}
  AND marketing_type = #{marketingType} AND marketing_activity_id = #{activityId}
  AND order_status IN (0, 1, 2) AND deleted = 0

SELECT COUNT(*)
FROM pt_product_store_rel
WHERE product_id = #{productId} AND store_id = #{storeId}

SELECT COUNT(*)
FROM pt_member_group_benefit
WHERE source_order_id = #{orderId}

SELECT 
FROM pt_private_order
WHERE member_id = #{userId} AND deleted = 0

    AND order_status = #{orderStatus}

ORDER BY id DESC

    LIMIT #{offset}, #{limit}
